#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

float corr = uTexSize.xy*texsize_noise_lq.zw;
vec2 arg;

int k2 = int(q29); //index4
int k1 = k2%4;
float clp = 8;

vec3 noiseVal =.03*(texture(sampler_noise_lq, vUv*.3+.01*rand_frame));

vec2 zz = (vUv-.5) *uTexSize.xy *.015*q27;
zz *= uAspect.zw;
zz =multiply(zz,mat2(_qa));

//zz = zz * cos(1/vRadius*8);
/// {zz = 5*(zz.xy+zz.yx);} //evtl,

if (k1==0) {arg = clamp(tan(zz),-clp,clp);}
else if (k1==1) {arg = clamp(tan(zz) / cos(zz.yx),-clp,clp);}
else if (k1==2) {arg = clamp(exp((zz.yx)),-clp,clp) ;}
else if (k1==3) {arg = clamp(sin(2*zz.yx),-clp,clp) ;}

//vec2 arg = (k1==0)*h1 + (k1==1)*h2 + (k1==2)*h3 + (k1==3)*h4;

//arg *= (zz+0.1);
if (k2 >= 4) {arg -= length(zz)/4;} //ja

//arg = atan(arg.yx*8);//ja, aber flimmer
//if (k2>=8) {arg = pow(arg,3);} // ja aber ohne das vorige
//g *= uAspect.xy * cos(16*(.5-vRadius)*vAngle); //ok
vUv += arg*uTexSize.zw* (1+ 4 * q28);

vec3 crisp = texture(sampler_main,vUv);

ret = q32*crisp + noiseVal*.8-.03;

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vec2 uv2;
float ang2, c, s;
vUv -= 0.5;
vUv *= uAspect.xy;

vec2 tmp = vUv;
float dist = 1;
float inten = 1;
float mask = 0;
ret1 = 0;
int anz = 4;
float n = 1;
vUv = multiply(vUv,mat2(_qa));
//vUv +=.3*q1;
while (n <= anz) {
    ang2 = 6.28*n/anz;
    c = cos(ang2);
    s = sin(ang2);
    uv2.x =  vUv.x*c - vUv.y*s;
    uv2.y =  vUv.x*s + vUv.y*c;
    uv2 *= uAspect.yx;
    dist = 1-fract(1.0/anz*n+q30); //evtl sqrt !
    inten =  pow(dist,.3)*(1-dist)*2;
    vec2 uv3 = 2*uv2*dist+.5;
    neu =  GetPixel (uv3);
    blur = GetBlur2 (uv3);
    neu += blur;
    ret1 = ret1*.9+neu*inten;
n++;
}


ret = ret1 + .5*vec3(0,0,.3)*vRadius ;


  fragColor = ret;
}
